function PBtn({ children, onClick, disabled, full, style: sx = {} }) {
  return (
    <button onClick={onClick} disabled={disabled}
      style={{background:disabled?BG:GRAD,border:"none",borderRadius:13,padding:"13px 22px",fontFamily:"Plus Jakarta Sans,sans-serif",fontWeight:800,fontSize:15,color:disabled?SUB:"#fff",cursor:disabled?"not-allowed":"pointer",opacity:disabled ? 0.5 : 1,transition:"all .15s",width:full?"100%":"auto",...sx}}
      onMouseOver={e=>{ if(!disabled){ e.currentTarget.style.filter="brightness(1.08)"; e.currentTarget.style.transform="translateY(-1px)"; e.currentTarget.style.boxShadow=`0 4px 14px rgba(233,30,140,.35)`; }}}
      onMouseOut={e=>{ e.currentTarget.style.filter="none"; e.currentTarget.style.transform="translateY(0)"; e.currentTarget.style.boxShadow="none"; }}
      onMouseDown={e=>{ if(!disabled){ e.currentTarget.style.transform="translateY(1px)"; e.currentTarget.style.filter="brightness(.95)"; }}}
      onMouseUp={e=>{ if(!disabled){ e.currentTarget.style.transform="translateY(-1px)"; e.currentTarget.style.filter="brightness(1.08)"; }}}>
      {children}
    </button>
  );
}

// ── Participant QR ──
function PQR({ p, code, size = 160 }) {
  const ref = useRef();
  const data = pNum(p.num); // encodes e.g. "P001" — matches what QR scanner expects
  useEffect(() => {
    if (!ref.current) return;
    function render() {
      if (!window.QRCode) return;
      ref.current.innerHTML = "";
      new window.QRCode(ref.current, {
        text: data,
        width: size - 24,
        height: size - 24,
        colorDark: PINK,
        colorLight: "#ffffff",
        correctLevel: window.QRCode.CorrectLevel.M,
      });
    }
    if (window.QRCode) { render(); }
    else {
      const s = document.createElement("script");
      s.src = "https://cdnjs.cloudflare.com/ajax/libs/qrcodejs/1.0.0/qrcode.min.js";
      s.onload = render;
      document.head.appendChild(s);
    }
  }, [data, size]);
  return (
    // colorScheme:"light" forces white background even on OS dark mode — QR must stay readable
    <div style={{width:size,height:size,background:"#fff",borderRadius:12,padding:12,border:`1px solid ${BORDER}`,display:"inline-flex",alignItems:"center",justifyContent:"center",colorScheme:"light"}}>
      <div ref={ref}/>
    </div>
  );
}

// ── Contacts picker ──
function Picker({ participants, groups, selId, onSelect, onClose }) {
  const [q, setQ] = useState("");
  const sorted = [...participants].sort((a,b) => a.num - b.num);
  const filt = sorted.filter(p => p.name.toLowerCase().includes(q.toLowerCase()) || pNum(p.num).includes(q.toUpperCase()));
  const grouped = {};
  filt.forEach(p => { const k = p.name[0].toUpperCase(); if (!grouped[k]) grouped[k]=[]; grouped[k].push(p); });
  const letters = Object.keys(grouped).sort();
  return (
    <div style={{position:"fixed",inset:0,zIndex:500,background:BG,display:"flex",flexDirection:"column",animation:"slideInRight .2s ease"}}>
      <div style={{background:"#fff",borderBottom:`1px solid ${BORDER}`,padding:"0 16px",height:54,display:"flex",alignItems:"center",gap:10,flexShrink:0}}>
        <button onClick={onClose} style={{background:"none",border:"none",cursor:"pointer",color:PINK,fontFamily:"Plus Jakarta Sans,sans-serif",fontWeight:700,fontSize:14}}>Cancel</button>
        <div style={{flex:1,textAlign:"center",fontFamily:"Plus Jakarta Sans,sans-serif",fontWeight:900,fontSize:16,color:TEXT}}>Select Participant</div>
        <div style={{width:56}}/>
      </div>
      <div style={{padding:"10px 16px",background:"#fff",borderBottom:`1px solid ${BORDER}`,flexShrink:0}}>
        <div style={{display:"flex",alignItems:"center",gap:8,background:"#fff",border:`1.5px solid ${BORDER}`,borderRadius:12,padding:"8px 14px"}}>
          <svg width="15" height="15" viewBox="0 0 24 24" fill="none" stroke={SUB} strokeWidth="2.2" strokeLinecap="round"><circle cx="11" cy="11" r="8"/><line x1="21" y1="21" x2="16.65" y2="16.65"/></svg>
          <input placeholder="Search name or number..." value={q} onChange={e=>setQ(e.target.value)} autoFocus style={{flex:1,background:"none",border:"none",fontFamily:"Poppins,sans-serif",fontSize:14,color:TEXT,outline:"none"}}/>
          {q && <button onClick={()=>setQ("")} style={{background:"none",border:"none",cursor:"pointer",color:SUB,fontSize:18}}>×</button>}
        </div>
      </div>
      <div style={{flex:1,overflowY:"auto"}}>
        {filt.length === 0 && <div style={{padding:48,textAlign:"center",color:SUB,fontSize:13}}>No participants found</div>}
        {q
          ? filt.map(p => <PRow key={p.id} p={p} groups={groups} sel={selId===p.id} onSelect={()=>{onSelect(p.id);onClose();}}/>)
          : letters.map(l => (
            <div key={l}>
              <div style={{padding:"6px 16px 4px",background:BG,fontFamily:"Plus Jakarta Sans,sans-serif",fontWeight:800,fontSize:12,color:SUB,borderBottom:`1px solid ${BORDER}`}}>{l}</div>
              {grouped[l].map(p => <PRow key={p.id} p={p} groups={groups} sel={selId===p.id} onSelect={()=>{onSelect(p.id);onClose();}}/>)}
            </div>
          ))
        }
        <div style={{height:32}}/>
      </div>
    </div>
  );
}

function PRow({ p, groups, sel, onSelect }) {
  const grp = groups.find(g => g.id === p.gid);
  return (
    <button onClick={onSelect} style={{width:"100%",display:"flex",alignItems:"center",gap:14,padding:"13px 16px",border:"none",background:sel?SOFT:"#fff",borderBottom:`1px solid ${BORDER}`,cursor:"pointer",textAlign:"left",borderLeft:sel?`3px solid ${PINK}`:"3px solid transparent",transition:".1s"}}>
      <Av s={p.av} color={grp?.color||BLUE} size={42}/>
      <div style={{flex:1}}>
        <div style={{fontFamily:"Plus Jakarta Sans,sans-serif",fontWeight:800,fontSize:15,color:TEXT,marginBottom:2}}>{p.name}</div>
        <div style={{display:"flex",alignItems:"center",gap:8}}>
          <span style={{fontFamily:"Plus Jakarta Sans,sans-serif",fontWeight:700,fontSize:11,color:SUB}}>{pNum(p.num)}</span>
          {grp && <span style={{fontSize:11,background:`${grp.color}18`,border:`1px solid ${grp.color}35`,color:grp.color,padding:"1px 8px",borderRadius:99,fontWeight:700}}>{grp.name}</span>}
          <span style={{fontSize:11,color:PINK,fontWeight:700}}>{p.total} coins</span>
        </div>
      </div>
      <div style={{color:BORDER,fontSize:20}}>›</div>
    </button>
  );
}

// ── Mass Give sheet ──
function MassGive({ participants, groups, session, onAward, onClose }) {
  const [amt, setAmt] = useState(null);
  const [cAmt, setCAmt] = useState("");
  const [scanLog, setScanLog] = useState([]);
  const [scanCount, setScanCount] = useState(0);
  const scanCountRef = useRef(0);
  const [scanning, setScanning] = useState(false);
  const [scanAttempt, setScanAttempt] = useState(0);
  const [scannerErr, setScannerErr] = useState("");
  const [flashName, setFlashName] = useState(null);
  const html5QrRef = useRef(null);
  const participantsRef = useRef(participants);
  const scanLogRef = useRef([]);
  const finalAmtRef = useRef(null);

  const finalAmt = amt === "custom" ? Number(cAmt) : amt;
  const ok = finalAmt !== null && finalAmt !== 0 && !isNaN(finalAmt);

  useEffect(() => { participantsRef.current = participants; }, [participants]);
  useEffect(() => { finalAmtRef.current = finalAmt; }, [finalAmt]);

  function startScanner() {
    if (!ok) return;
    setScannerErr("");
    scanLogRef.current = [];
    scanCountRef.current = 0;
    setScanCount(0);
    setScanAttempt(n => n + 1);
    setScanning(true);
  }

  function stopScanner() {
    if (html5QrRef.current) { html5QrRef.current.stop().catch(()=>{}); html5QrRef.current = null; }
    setScanning(false);
    setFlashName(null);
  }

  useEffect(() => {
    if (!scanning) return;
    const containerId = `tc-qr-scanner-${scanAttempt}`;
    function initScanner() {
      if (!window.Html5Qrcode) { setScannerErr("Camera library failed to load."); setScanning(false); return; }
      try {
        const scanner = new window.Html5Qrcode(containerId);
        html5QrRef.current = scanner;
        scanner.start(
          { facingMode: "environment" },
          { fps: 15, qrbox: (vw) => ({ width: Math.min(vw * 0.65, 280), height: Math.min(vw * 0.65, 280) }), aspectRatio: window.innerHeight / window.innerWidth, videoConstraints: { facingMode: "environment", advanced: [{zoom: 2.0}] } },
          (decodedText) => {
            const raw = decodedText.replace(/^P/i,"").trim();
            const num = parseInt(raw);
            if (isNaN(num)) return;
            const p = participantsRef.current.find(x => x.num === num);
            if (!p) return;
            // 2-second cooldown per participant
            const now = Date.now();
            const existing = scanLogRef.current.find(l => l.id === p.id);
            if (existing && now - existing.ts < 2000) return;
            if (existing) { existing.ts = now; } else { scanLogRef.current = [...scanLogRef.current, {id: p.id, ts: now}]; }
            onAward(p.id, "token", finalAmtRef.current);
            scanCountRef.current += 1;
            setScanCount(scanCountRef.current);
            const entry = {...p, t: new Date().toLocaleTimeString()};
            setScanLog(prev => [entry, ...prev.filter(x => x.id !== p.id)]);
            setFlashName({name: p.name, pts: finalAmtRef.current});
            setTimeout(() => setFlashName(null), 1200);
          },
          () => {}
        ).catch(() => {
          html5QrRef.current = null;
          setScannerErr("Camera access denied. Allow camera access in your browser settings and try again.");
          setScanning(false);
        });
      } catch(e) { setScannerErr("Could not start camera. Tap Open Camera to try again."); setScanning(false); }
    }
    if (window.Html5Qrcode) { initScanner(); }
    else {
      const s = document.createElement("script");
      s.src = "https://cdnjs.cloudflare.com/ajax/libs/html5-qrcode/2.3.8/html5-qrcode.min.js";
      s.onload = initScanner;
      s.onerror = () => { setScannerErr("Failed to load camera library."); setScanning(false); };
      document.head.appendChild(s);
    }
    return () => { if (html5QrRef.current) { html5QrRef.current.stop().catch(()=>{}); html5QrRef.current = null; } };
  }, [scanning, scanAttempt]); // eslint-disable-line react-hooks/exhaustive-deps

  return (
    <div className="tc-modal-backdrop" style={{position:"fixed",inset:0,zIndex:450}}>
      <div onClick={onClose} style={{position:"absolute",inset:0,background:"rgba(26,10,20,.45)",backdropFilter:"blur(3px)"}}/>
      <div className="tc-modal-sheet" style={{background:"#fff",maxHeight:"90vh",display:"flex",flexDirection:"column",animation:"slideUp .25s ease"}}>
        <div style={{padding:"14px 20px 0",flexShrink:0}}>
          <div style={{width:36,height:4,background:BORDER,borderRadius:4,margin:"0 auto 14px"}}/>
          <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:16}}>
            <div style={{fontFamily:"Plus Jakarta Sans,sans-serif",fontWeight:900,fontSize:18,color:TEXT}}>Scan QR to Give</div>
            <button onClick={onClose} style={{background:"none",border:"none",cursor:"pointer",color:SUB,fontSize:20,lineHeight:1,padding:"4px 6px"}}>×</button>
          </div>
        </div>
        <div style={{flex:1,overflowY:"auto",padding:"0 20px 32px"}}>
          {/* Step 1 — coin amount */}
          <SL style={{marginBottom:8}}>Choose amount to give</SL>
          <div style={{display:"grid",gridTemplateColumns:"repeat(3,1fr)",gap:8,marginBottom:10}}>
            {(session?.otherCoins || TV_DEFAULT).map(v => (
              <button key={v} onClick={()=>{setAmt(v);setCAmt("");}}
                style={{padding:"16px 8px",borderRadius:12,cursor:"pointer",fontFamily:"Plus Jakarta Sans,sans-serif",fontWeight:900,fontSize:20,background:amt===v?GRAD:"#fff",border:amt===v?`2px solid transparent`:`1.5px solid ${BORDER}`,color:amt===v?"#fff":v<0?"#EF4444":PINK,transition:"all .12s"}}>
                {v>0?"+":""}{v}
              </button>
            ))}
          </div>
          <input type="number" placeholder="Custom amount…" value={cAmt} onChange={e=>{setCAmt(e.target.value);setAmt("custom");}}
            style={{width:"100%",background:"#FFF5FA",border:`1.5px solid ${amt==="custom"?PINK:"#F9A8D4"}`,borderRadius:12,padding:"10px 14px",fontFamily:"Poppins,sans-serif",fontSize:13,color:TEXT,outline:"none",marginBottom:16}}/>

          {/* Open Camera button */}
          {!scanning && (
            <button onClick={()=>{ if(!ok){return;} startScanner(); }}
              style={{width:"100%",padding:"14px 0",background:ok?GRAD:"#F3F4F6",border:"none",borderRadius:13,fontFamily:"Plus Jakarta Sans,sans-serif",fontWeight:800,fontSize:15,color:ok?"#fff":"#9CA3AF",cursor:ok?"pointer":"default",display:"flex",alignItems:"center",justifyContent:"center",gap:10,marginBottom:ok?0:0}}>
              <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.2" strokeLinecap="round"><path d="M23 19a2 2 0 0 1-2 2H3a2 2 0 0 1-2-2V8a2 2 0 0 1 2-2h4l2-3h6l2 3h4a2 2 0 0 1 2 2z"/><circle cx="12" cy="13" r="4"/></svg>
              {ok ? "Open Camera to Scan QR" : "Select an amount first"}
            </button>
          )}

          {/* Camera error */}
          {scannerErr && (
            <div style={{background:"#FEF2F2",border:"1px solid #FCA5A5",borderRadius:12,padding:"14px",marginTop:10,fontSize:12,color:"#7F1D1D",lineHeight:1.7}}>
              {scannerErr}
              <button onClick={()=>{ setScannerErr(""); }} style={{display:"block",marginTop:8,padding:"8px 16px",background:"#EF4444",border:"none",borderRadius:8,fontFamily:"Plus Jakarta Sans,sans-serif",fontWeight:700,fontSize:12,color:"#fff",cursor:"pointer"}}>Back</button>
            </div>
          )}

          {/* Scan log */}
          {scanLog.length > 0 && (
            <div style={{borderRadius:12,border:`1px solid ${BORDER}`,overflow:"hidden",marginTop:14}}>
              <div style={{padding:"8px 12px",background:BG,fontSize:11,fontFamily:"Plus Jakarta Sans,sans-serif",fontWeight:800,color:SUB,textTransform:"uppercase",letterSpacing:1,borderBottom:`1px solid ${BORDER}`}}>
                Scanned ({scanLog.length})
              </div>
              {scanLog.map((p,i) => {
                const grp = groups.find(g=>g.id===p.gid);
                return (
                  <div key={i} style={{display:"flex",alignItems:"center",gap:10,padding:"9px 12px",borderBottom:`1px solid ${BORDER}`,background:i===0?SOFT:"#fff"}}>
                    <div style={{width:6,height:6,borderRadius:"50%",background:GREEN,flexShrink:0}}/>
                    <span style={{fontSize:11,fontFamily:"Plus Jakarta Sans,sans-serif",fontWeight:800,color:PINK,minWidth:36}}>{pNum(p.num)}</span>
                    <Av s={p.av} color={grp?.color||BLUE} size={26}/>
                    <span style={{flex:1,fontFamily:"Plus Jakarta Sans,sans-serif",fontWeight:700,fontSize:13,color:TEXT}}>{p.name}</span>
                    <span style={{fontFamily:"Plus Jakarta Sans,sans-serif",fontWeight:900,fontSize:13,color:GREEN}}>+{finalAmt}</span>
                    <span style={{fontSize:10,color:SUB}}>{p.t}</span>
                  </div>
                );
              })}
            </div>
          )}
        </div>
      </div>

      {/* Full-screen camera overlay */}
      {scanning && (
        <div style={{position:"fixed",inset:0,zIndex:9999,background:"#000",display:"flex",flexDirection:"column"}}>
          <div id={`tc-qr-scanner-${scanAttempt}`} style={{flex:1,width:"100%"}}/>
          {flashName && (
            <div style={{position:"absolute",inset:0,display:"flex",alignItems:"center",justifyContent:"center",pointerEvents:"none",zIndex:10000}}>
              <div style={{background:"rgba(0,0,0,.7)",borderRadius:20,padding:"28px 40px",textAlign:"center",border:`3px solid ${GREEN}`,animation:"qrFlash .35s ease-out"}}>
                <div style={{fontSize:52,fontFamily:"Plus Jakarta Sans,sans-serif",fontWeight:900,color:GREEN,lineHeight:1}}>{flashName.pts>0?"+":""}{flashName.pts}</div>
                <div style={{fontSize:20,fontFamily:"Plus Jakarta Sans,sans-serif",fontWeight:700,color:"#fff",marginTop:8}}>{flashName.name}</div>
              </div>
            </div>
          )}
          <div style={{position:"absolute",bottom:0,left:0,right:0,background:"rgba(0,0,0,.75)",backdropFilter:"blur(10px)",padding:"16px 20px 40px",display:"flex",flexDirection:"column",gap:10}}>
            <div style={{display:"flex",justifyContent:"space-between",alignItems:"center"}}>
              <div style={{fontSize:13,color:"rgba(255,255,255,.8)",fontWeight:600}}>
                {scanCount===0?"Point camera at participant's QR code":`✓ ${scanCount} scanned`}
              </div>
              <div style={{fontSize:14,color:PINK,fontWeight:900}}>{finalAmt>0?"+":""}{finalAmt}</div>
            </div>
            <button onClick={stopScanner}
              style={{width:"100%",padding:"14px 0",background:"rgba(255,255,255,.12)",border:"1.5px solid rgba(255,255,255,.25)",borderRadius:13,fontFamily:"Plus Jakarta Sans,sans-serif",fontWeight:700,fontSize:14,color:"#fff",cursor:"pointer"}}>
              Done
            </button>
          </div>
        </div>
      )}
    </div>
  );
}

// ── Coin Customizer modal ──
function CoinCustomizer({ session, onSave, onClose }) {
  const initOther = session.otherCoins || TV_DEFAULT;

  const [other, setOther] = useState([...initOther]);
  const [newVal, setNewVal] = useState("");

  function addOther() {
    const n = parseInt(newVal);
    if (isNaN(n)) return;
    if (other.length >= 15) return;
    setOther(prev => [...prev, n]);
    setNewVal("");
  }

  function removeOther(i) { setOther(prev => prev.filter((_,idx)=>idx!==i)); }

  function save() { onSave({ quickCoins: session.quickCoins || ACTS_DEFAULT.map(a=>a.pts), otherCoins: other }); onClose(); }

  return (
    <div className="tc-modal-backdrop" style={{position:"fixed",inset:0,zIndex:600}}>
      <div onClick={onClose} style={{position:"absolute",inset:0,background:"rgba(26,10,20,.5)",backdropFilter:"blur(3px)"}}/>
      <div className="tc-modal-sheet" style={{background:"#fff",maxHeight:"85vh",display:"flex",flexDirection:"column",animation:"slideUp .25s ease"}}>
        <div style={{padding:"14px 20px 0",flexShrink:0}}>
          <div style={{width:36,height:4,background:BORDER,borderRadius:4,margin:"0 auto 14px"}}/>
          <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:14}}>
            <div style={{fontFamily:"Plus Jakarta Sans,sans-serif",fontWeight:900,fontSize:18,color:TEXT}}>Customise Coins</div>
            <button onClick={onClose} style={{background:"none",border:"none",cursor:"pointer",color:SUB,fontSize:20,lineHeight:1,padding:"4px 6px"}}>×</button>
          </div>
        </div>

        <div style={{overflowY:"auto",flex:1,padding:"0 20px 24px"}}>
          <div style={{fontSize:13,color:SUB,marginBottom:14,fontWeight:500,lineHeight:1.6}}>
            Drag <svg width="10" height="13" viewBox="0 0 10 16" fill="none" style={{verticalAlign:"middle",margin:"0 2px"}}><circle cx="3" cy="2" r="1.5" fill="#9CA3AF"/><circle cx="7" cy="2" r="1.5" fill="#9CA3AF"/><circle cx="3" cy="8" r="1.5" fill="#9CA3AF"/><circle cx="7" cy="8" r="1.5" fill="#9CA3AF"/><circle cx="3" cy="14" r="1.5" fill="#9CA3AF"/><circle cx="7" cy="14" r="1.5" fill="#9CA3AF"/></svg> to reorder · Up to 15 values
          </div>

          <div style={{background:"#fff",border:`1.5px solid ${BORDER}`,borderRadius:14,overflow:"visible",marginBottom:16}}>
            {other.length === 0 && (
              <div style={{padding:"20px",textAlign:"center",fontSize:13,color:SUB}}>No coins yet.</div>
            )}
            <DraggableCoinList coins={other} setCoins={setOther} onRemove={removeOther}/>
          </div>

          <div style={{display:"flex",gap:8,marginBottom:14}}>
            <input type="number" placeholder="Enter value (e.g. 200 or −50)" value={newVal}
              onChange={e=>setNewVal(e.target.value)} onKeyDown={e=>e.key==="Enter"&&addOther()}
              style={{flex:1,background:"#fff",border:`1.5px solid ${BORDER}`,borderRadius:12,padding:"10px 14px",fontFamily:"Poppins,sans-serif",fontSize:13,color:TEXT,outline:"none"}}/>
            <button onClick={addOther} disabled={other.length>=15||!newVal}
              style={{padding:"0 16px",background:other.length>=15?BG:GRAD,border:"none",borderRadius:12,fontFamily:"Plus Jakarta Sans,sans-serif",fontWeight:800,fontSize:13,color:other.length>=15?SUB:"#fff",cursor:other.length>=15?"not-allowed":"pointer"}}>
              Add
            </button>
          </div>

          <div style={{background:`${PINK}10`,border:`1px solid ${PINK}25`,borderRadius:10,padding:"10px 12px",marginTop:8,fontSize:12,color:PINK,fontWeight:600}}>
            Negative values (e.g. −50) will subtract coins — participants can go below zero on the scoreboard.
          </div>
        </div>

        <div style={{padding:"0 20px 32px",flexShrink:0}}>
          <button onClick={save} style={{width:"100%",padding:"14px 0",background:GRAD,border:"none",borderRadius:13,fontFamily:"Plus Jakarta Sans,sans-serif",fontWeight:800,fontSize:15,color:"#fff",cursor:"pointer"}}>
            Save Coin Settings
          </button>
        </div>
      </div>
    </div>
  );
}

// ── Session Settings sheet (gear next to session name in session list) ──
function SessionSettings({ session, isPro=false, atLimit=false, existingSessionNames=[], onRename, onToggleLive, onExport, onExportLog, onReset, onDuplicate, onArchive, onClose }) {
  const [editing, setEditing] = useState(false);
  const [nameVal, setNameVal] = useState(session.name); // eslint-disable-line
  const [nameErr, setNameErr] = useState("");

  function saveName() {
    const trimmed = nameVal.trim();
    if (!trimmed) return;
    if (trimmed === session.name) { setEditing(false); setNameErr(""); return; }
    const duplicate = existingSessionNames.some(n => n.toLowerCase() === trimmed.toLowerCase() && n.toLowerCase() !== session.name.toLowerCase());
    if (duplicate) { setNameErr(`A session named "${trimmed}" already exists. Please choose a different name.`); return; }
    onRename(trimmed); setEditing(false); setNameErr("");
  }

  return (
    <div className="tc-modal-backdrop" style={{position:"fixed",inset:0,zIndex:500}}>
      <div onClick={onClose} style={{position:"absolute",inset:0,background:"rgba(26,10,20,.45)",backdropFilter:"blur(3px)"}}/>
      <div className="tc-modal-sheet" style={{background:"#fff",animation:"slideUp .25s ease",maxHeight:"90vh",overflowY:"auto"}}>
        <div style={{padding:"14px 20px 0"}}>
          <div style={{width:36,height:4,background:BORDER,borderRadius:4,margin:"0 auto 16px"}}/>
          <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:20}}>
            <div style={{fontFamily:"Plus Jakarta Sans,sans-serif",fontWeight:900,fontSize:18,color:TEXT}}>Session Settings</div>
            <button onClick={onClose} style={{background:"none",border:"none",cursor:"pointer",color:SUB,fontSize:20,lineHeight:1,padding:"4px 6px"}}>×</button>
          </div>
        </div>
        <div style={{padding:"0 20px 36px",display:"flex",flexDirection:"column",gap:10}}>
          {/* Session name edit */}
          <div style={{background:BG,borderRadius:14,padding:"14px 16px"}}>
            <div style={{fontSize:11,fontWeight:700,color:SUB,textTransform:"uppercase",letterSpacing:1,marginBottom:8,fontFamily:"Poppins,sans-serif"}}>Session Name</div>
            {editing ? (
              <div style={{display:"flex",flexDirection:"column",gap:6}}>
                <div style={{display:"flex",gap:8}}>
                  <input value={nameVal} onChange={e=>{setNameVal(e.target.value);setNameErr("");}} onKeyDown={e=>e.key==="Enter"&&saveName()} autoFocus
                    style={{flex:1,background:"#fff",border:`1.5px solid ${nameErr?"#EF4444":PINK}`,borderRadius:10,padding:"10px 12px",fontFamily:"Plus Jakarta Sans,sans-serif",fontWeight:700,fontSize:15,color:TEXT,outline:"none"}}/>
                  <button onClick={saveName} style={{padding:"0 16px",background:GRAD,border:"none",borderRadius:10,fontFamily:"Plus Jakarta Sans,sans-serif",fontWeight:800,fontSize:13,color:"#fff",cursor:"pointer"}}>Save</button>
                  <button onClick={()=>{setNameVal(session.name);setEditing(false);setNameErr("");}} style={{padding:"0 12px",background:"none",border:`1px solid ${BORDER}`,borderRadius:10,fontFamily:"Plus Jakarta Sans,sans-serif",fontWeight:700,fontSize:13,color:SUB,cursor:"pointer"}}>Cancel</button>
                </div>
                {nameErr && <div style={{fontSize:11,color:"#EF4444",fontWeight:600,lineHeight:1.5,padding:"0 2px"}}>{nameErr}</div>}
              </div>
            ) : (
              <div style={{display:"flex",alignItems:"center",justifyContent:"space-between"}}>
                <div style={{fontFamily:"Plus Jakarta Sans,sans-serif",fontWeight:800,fontSize:16,color:TEXT}}>{session.name}</div>
                <button onClick={()=>setEditing(true)} style={{background:"none",border:`1px solid ${BORDER}`,borderRadius:8,padding:"5px 12px",fontSize:12,color:SUB,cursor:"pointer",fontFamily:"Plus Jakarta Sans,sans-serif",fontWeight:700}}>Edit</button>
              </div>
            )}
            <div style={{fontSize:11,color:SUB,marginTop:4}}>Code: {session.code} · {session.participants.length} participants</div>
          </div>

          {/* Duplicate — first after session name */}
          <button onClick={atLimit ? undefined : onDuplicate} disabled={atLimit}
            title={atLimit ? "Session limit reached — upgrade to Pro for unlimited sessions" : "Duplicate this session"}
            style={{width:"100%",padding:"13px 0",background:"#fff",border:`1.5px solid ${atLimit?"#E5E7EB":"#1A0A14"}`,borderRadius:999,fontFamily:"Plus Jakarta Sans,sans-serif",fontWeight:800,fontSize:14,color:atLimit?"#9CA3AF":"#1A0A14",cursor:atLimit?"not-allowed":"pointer",display:"flex",alignItems:"center",justifyContent:"center",gap:6}}>
            Duplicate Session
            {atLimit && <span style={{fontSize:11,fontWeight:700,background:"#F3F4F6",border:"1px solid #E5E7EB",borderRadius:99,padding:"2px 8px",color:"#9CA3AF"}}>Limit reached</span>}
          </button>

          {/* Export Participants — Pro only */}
          {isPro ? (
            <button onClick={onExport} style={{width:"100%",padding:"13px 0",background:"#fff",border:"1.5px solid #1A0A14",borderRadius:999,fontFamily:"Plus Jakarta Sans,sans-serif",fontWeight:800,fontSize:14,color:"#1A0A14",cursor:"pointer",display:"flex",alignItems:"center",justifyContent:"center",gap:6}}>
              <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round"><path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4"/><polyline points="7 10 12 15 17 10"/><line x1="12" y1="15" x2="12" y2="3"/></svg>
              Export Participants CSV
            </button>
          ) : (
            <button onClick={()=>{}} style={{width:"100%",padding:"13px 0",background:"#F9FAFB",border:"1.5px solid #E5E7EB",borderRadius:999,fontFamily:"Plus Jakarta Sans,sans-serif",fontWeight:800,fontSize:14,color:"#9CA3AF",cursor:"not-allowed",display:"flex",alignItems:"center",justifyContent:"center",gap:6}}>
              <svg width="12" height="12" viewBox="0 0 32 32" xmlns="http://www.w3.org/2000/svg"><path d="m2.8373 20.9773c-.6083-3.954-1.2166-7.9079-1.8249-11.8619-.1349-.8765.8624-1.4743 1.5718-.9422 1.8952 1.4214 3.7903 2.8427 5.6855 4.2641.624.468 1.513.3157 1.9456-.3333l4.7333-7.1c.5002-.7503 1.6026-.7503 2.1028 0l4.7333 7.1c.4326.649 1.3216.8012 1.9456.3333 1.8952-1.4214 3.7903-2.8427 5.6855-4.2641.7094-.5321 1.7067.0657 1.5719.9422-.6083 3.954-1.2166 7.9079-1.8249 11.8619z" fill="#ffb743"/><path d="m27.7902 27.5586h-23.5804c-.758 0-1.3725-.6145-1.3725-1.3725v-3.015h26.3255v3.015c-.0001.758-.6146 1.3725-1.3726 1.3725z" fill="#ffb743"/></svg>
              Export Participants CSV — Pro
            </button>
          )}

          {/* Export Log — free for all */}
          <button onClick={onExportLog} style={{width:"100%",padding:"13px 0",background:"#fff",border:"1.5px solid #1A0A14",borderRadius:999,fontFamily:"Plus Jakarta Sans,sans-serif",fontWeight:800,fontSize:14,color:"#1A0A14",cursor:"pointer",display:"flex",alignItems:"center",justifyContent:"center",gap:6}}>
            <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round"><path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4"/><polyline points="7 10 12 15 17 10"/><line x1="12" y1="15" x2="12" y2="3"/></svg>
            Export Activity Log CSV
          </button>

          {/* Reset */}
          <button onClick={onReset} style={{width:"100%",padding:"13px 0",background:"#FEF2F2",border:"1.5px solid #EF444440",borderRadius:999,fontFamily:"Plus Jakarta Sans,sans-serif",fontWeight:800,fontSize:14,color:"#EF4444",cursor:"pointer"}}>
            Reset All Coins
          </button>

          <div style={{height:1,background:BORDER,margin:"4px 0"}}/>

          {/* Archive */}
          <div style={{background:"#F8F8FA",border:`1px solid ${BORDER}`,borderRadius:13,padding:"14px 16px"}}>
            <div style={{display:"flex",alignItems:"center",gap:8,marginBottom:4}}>
              <svg width="15" height="15" viewBox="0 0 24 24" fill="none" stroke={SUB} strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><polyline points="21 8 21 21 3 21 3 8"/><rect x="1" y="3" width="22" height="5"/><line x1="10" y1="12" x2="14" y2="12"/></svg>
              <div style={{fontFamily:"Plus Jakarta Sans,sans-serif",fontWeight:800,fontSize:14,color:TEXT}}>Archive Session</div>
            </div>
            <div style={{fontSize:12,color:SUB,marginBottom:12,lineHeight:1.6}}>
              Moves the session out of your active list. Participants can no longer join, but all data is preserved. You can unarchive it anytime.
            </div>
            <button onClick={onArchive}
              style={{width:"100%",padding:"11px 0",background:"#1A0A14",border:"none",borderRadius:10,fontFamily:"Plus Jakarta Sans,sans-serif",fontWeight:800,fontSize:13,color:"#fff",cursor:"pointer"}}>
              Archive Session
            </button>
          </div>
        </div>
      </div>
    </div>
  );
}

