function TipsPage({ onClose }) {
  const [activeTool, setActiveTool] = useState(0);
  const [activeTip, setActiveTip] = useState(0);
  const tool = TIPS_DATA[activeTool];
  return (
    <div style={{position:"fixed",inset:0,zIndex:3000,background:"rgba(10,10,15,.6)",backdropFilter:"blur(6px)",display:"flex",alignItems:"center",justifyContent:"center",padding:16}}>
      <style>{`
        @keyframes tpSlideIn{from{opacity:0;transform:translateY(18px) scale(.97)}to{opacity:1;transform:none}}
        @keyframes tpFadeIn{from{opacity:0}to{opacity:1}}
        .tp-tool-btn{border:none;cursor:pointer;border-radius:12px;padding:8px 14px;font-family:'Plus Jakarta Sans',sans-serif;font-weight:700;font-size:12px;transition:all .18s;display:flex;align-items:center;gap:6px;white-space:nowrap;}
        .tp-tip-card{border-radius:16px;padding:20px;cursor:pointer;transition:all .18s;border:2px solid transparent;}
        .tp-tip-card:hover{transform:translateY(-2px);}
      `}</style>
      <div style={{background:"#fff",borderRadius:24,width:"100%",maxWidth:680,maxHeight:"90vh",display:"flex",flexDirection:"column",overflow:"hidden",animation:"tpSlideIn .3s cubic-bezier(.22,1,.36,1) both",boxShadow:"0 32px 80px rgba(0,0,0,.28)"}}>
        {/* Header */}
        <div style={{padding:"20px 24px 0",display:"flex",alignItems:"center",justifyContent:"space-between",flexShrink:0}}>
          <div>
            <div style={{fontFamily:"'Plus Jakarta Sans',sans-serif",fontWeight:800,fontSize:18,color:"#0A0A0F"}}>Host Tips 💡</div>
            <div style={{fontSize:12,color:"#6B7280",marginTop:2}}>Creative ways to use each giving method</div>
          </div>
          <button onClick={onClose} style={{background:"none",border:"none",cursor:"pointer",fontSize:22,color:"#9CA3AF",lineHeight:1,padding:"4px 6px"}}>×</button>
        </div>
        {/* Tool tabs */}
        <div style={{display:"flex",gap:6,padding:"16px 24px 0",overflowX:"auto",flexShrink:0,scrollbarWidth:"none"}}>
          {TIPS_DATA.map((t,i) => (
            <button key={t.tool} className="tp-tool-btn"
              onClick={()=>{setActiveTool(i);setActiveTip(0);}}
              style={{background:activeTool===i?t.color:"#F3F4F6",color:activeTool===i?"#fff":"#6B7280",
                boxShadow:activeTool===i?`0 4px 16px ${t.color}44`:"none"}}>
              <t.Icon c={activeTool===i?"#fff":t.color} s={14}/>{t.tool}
            </button>
          ))}
        </div>
        {/* Tips list */}
        <div style={{flex:1,overflowY:"auto",padding:"16px 24px 24px",display:"flex",flexDirection:"column",gap:10}}>
          {tool.tips.map((tip,i) => (
            <div key={tip.title} className="tp-tip-card"
              onClick={()=>setActiveTip(activeTip===i?-1:i)}
              style={{background:activeTip===i?tool.bg:"#FAFAFA",borderColor:activeTip===i?tool.color:"transparent"}}>
              <div style={{display:"flex",alignItems:"center",gap:10}}>
                <div style={{width:36,height:36,borderRadius:10,background:activeTip===i?tool.color:tool.bg,display:"flex",alignItems:"center",justifyContent:"center",flexShrink:0,transition:"all .18s"}}>
                  <tool.Icon c={activeTip===i?"#fff":tool.color} s={18}/>
                </div>
                <div style={{flex:1}}>
                  <div style={{fontFamily:"'Plus Jakarta Sans',sans-serif",fontWeight:700,fontSize:14,color:"#0A0A0F"}}>{tip.title}</div>
                </div>
                <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="#9CA3AF" strokeWidth="2.5" strokeLinecap="round"
                  style={{flexShrink:0,transform:activeTip===i?"rotate(180deg)":"rotate(0deg)",transition:"transform .2s"}}>
                  <polyline points="6 9 12 15 18 9"/>
                </svg>
              </div>
              {activeTip===i && (
                <div style={{marginTop:12,paddingTop:12,borderTop:`1px solid ${tool.color}30`,fontSize:13,color:"#374151",lineHeight:1.75,animation:"tpFadeIn .2s ease"}}>
                  {tip.body}
                </div>
              )}
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}

